async (page) => {
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 219, y: 112});
  await page.waitForTimeout(5000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const logCount = parsed.inventory.filter(i => i.key === 'logs').reduce((sum, i) => sum + i.count, 0);
  return JSON.stringify({ logs: logCount, pos: parsed.player_position, current_target: parsed.current_target ? parsed.current_target.name : null });
}

